cssRequirements.css:
@layer priority1 {
  .basex-radio-root[data-checked] {
    border-color: var(--colorPrimary);
    background-color: var(--colorPrimary);
  }
  .basex-radio-indicator {
    opacity: 1;
    transform: scale(1);
    transition:
      opacity 100ms ease-out,
      transform 100ms ease-out;
  }
  .basex-radio-indicator[data-unchecked] {
    opacity: 0;
    transform: scale(0.5);
  }
}
